   1→const { app, BrowserWindow, ipcMain, dialog } = require('electron');
   2→const path = require('path');
   3→const { spawn } = require('child_process');
   4→const fs = require('fs');
   5→const https = require('https');
   6→const http = require('http');
   7→const crypto = require('crypto');
   8→
   9→// 百度翻译API配置
  10→const TRANSLATE_CONFIG_PATH = path.join(require('os').homedir(), '.clawdbot', 'translate_config.json');
  11→const BAIDU_LANG_MAP = { en:'en', ja:'jp', ko:'kor', fr:'fra', de:'de', ru:'ru', es:'spa', pt:'pt', it:'it', ar:'ara', th:'th', vi:'vie', id:'id', ms:'may', hi:'hi' };
  12→
  13→function loadTranslateConfig() {
  14→  try { return JSON.parse(fs.readFileSync(TRANSLATE_CONFIG_PATH, 'utf-8')); } catch(e) { return {}; }
  15→}
  16→
  17→function baiduTranslate(text, fromLang) {
  18→  return new Promise((resolve) => {
  19→    const cfg = loadTranslateConfig();
  20→    const appid = cfg.baidu_appid || '', key = cfg.baidu_key || '';
  21→    if (!appid || !key) { resolve(null); return; }
  22→    const salt = String(Math.floor(Math.random() * 90000) + 10000);
  23→    const sign = crypto.createHash('md5').update(appid + text + salt + key).digest('hex');
  24→    const params = new URLSearchParams({ q: text, from: BAIDU_LANG_MAP[fromLang] || 'auto', to: 'zh', appid, salt, sign });
  25→    https.get('https://fanyi-api.baidu.com/api/trans/vip/translate?' + params, (res) => {
  26→      let d = ''; res.on('data', c => d += c);
  27→      res.on('end', () => {
  28→        try {
  29→          const json = JSON.parse(d);
  30→          if (json.trans_result) resolve(json.trans_result.map(r => r.dst).join('\n'));
  31→          else resolve(null);
  32→        } catch(e) { resolve(null); }
  33→      });
  34→    }).on('error', () => resolve(null));
  35→  });
  36→}
  37→
  38→let mainWindow;
  39→let db = null;
  40→let userDb = null;
  41→let currentLangGlobal = 'en';
  42→
  43→const BIN_DIR = app.isPackaged
  44→  ? path.join(process.resourcesPath, 'bin')
  45→  : path.join('E:', '视频下载器具', 'bin');
  46→const YTDLP = path.join(BIN_DIR, 'yt-dlp.exe');
  47→const FFMPEG_DIR = BIN_DIR;
  48→const USER_DATA = app.isPackaged ? path.join(app.getPath('userData')) : __dirname;
  49→const DOWNLOADS = path.join(USER_DATA, 'downloads');
  50→const AI_CONFIG_FILE = path.join(USER_DATA, 'ai_config.json');
  51→
  52→// 6家AI预设 + 自定义
  53→const AI_PROVIDERS = {
  54→  openai:   { name: 'OpenAI',        baseUrl: 'https://api.openai.com/v1',              model: 'gpt-4o-mini' },
  55→  claude:   { name: 'Claude',        baseUrl: 'https://api.anthropic.com/v1',           model: 'claude-sonnet-4-20250514' },
  56→  groq:     { name: 'Groq',          baseUrl: 'https://api.groq.com/openai/v1',         model: 'llama-3.3-70b-versatile' },
  57→  deepseek: { name: 'DeepSeek(深度求索)', baseUrl: 'https://api.deepseek.com/v1',            model: 'deepseek-chat' },
  58→  qwen:     { name: 'Qwen(通义千问)',    baseUrl: 'https://dashscope.aliyuncs.com/compatible-mode/v1', model: 'qwen-plus' },
  59→  zhipu:    { name: 'Zhipu(智谱清言)',   baseUrl: 'https://open.bigmodel.cn/api/paas/v4',  model: 'glm-4-flash' },
  60→  custom:   { name: '自定义(OpenAI兼容)', baseUrl: '',                                       model: '' }
  61→};
  62→
  63→function loadAIConfig() {
  64→  try {
  65→    if (fs.existsSync(AI_CONFIG_FILE)) return JSON.parse(fs.readFileSync(AI_CONFIG_FILE, 'utf-8'));
  66→  } catch(e) {}
  67→  // 从环境变量读取
  68→  const envKey = process.env.ANTHROPIC_AUTH_TOKEN || process.env.OPENAI_API_KEY || '';
  69→  const envBase = process.env.ANTHROPIC_BASE_URL || '';
  70→  const envModel = process.env.ANTHROPIC_DEFAULT_MODEL || '';
  71→  if (envKey) {
  72→    return { provider: envBase ? 'custom' : 'claude', apiKey: envKey, baseUrl: envBase, model: envModel };
  73→  }
  74→  return { provider: 'deepseek', apiKey: '', baseUrl: '', model: '' };
  75→}
  76→function saveAIConfig(cfg) { fs.writeFileSync(AI_CONFIG_FILE, JSON.stringify(cfg, null, 2)); }
  77→
  78→// 通用AI调用 (OpenAI兼容格式, Claude单独处理)
  79→function callAI(prompt) {
  80→  return new Promise((resolve) => {
  81→    const cfg = loadAIConfig();
  82→    if (!cfg.apiKey) { resolve(null); return; }
  83→
  84→    const preset = AI_PROVIDERS[cfg.provider] || {};
  85→    const baseUrl = cfg.baseUrl || preset.baseUrl || '';
  86→    const model = cfg.model || preset.model || '';
  87→    const maxTokens = cfg.maxTokens || 1024;
  88→    const temperature = cfg.temperature !== null && cfg.temperature !== undefined ? cfg.temperature : undefined;
  89→    if (!baseUrl) { resolve(null); return; }
  90→
  91→    const isClaude = cfg.provider === 'claude' || (model && model.toLowerCase().includes('claude'));
  92→    const urlObj = new URL(isClaude ? baseUrl + '/messages' : baseUrl + '/chat/completions');
  93→    const isHttps = urlObj.protocol === 'https:';
  94→
  95→    let body, headers;
  96→    if (isClaude) {
  97→      const bodyObj = { model, max_tokens: maxTokens, messages: [{ role: 'user', content: prompt }] };
  98→      if (temperature !== undefined) bodyObj.temperature = temperature;
  99→      body = JSON.stringify(bodyObj);
 100→      headers = {
 101→        'Content-Type': 'application/json',
 102→        'x-api-key': cfg.apiKey,
 103→        'anthropic-version': '2023-06-01'
 104→      };
 105→    } else {
 106→      const bodyObj = {
 107→        model, max_tokens: maxTokens,
 108→        messages: [
 109→          { role: 'system', content: '你是一个专业的多语言词典和语言学习助手。所有释义、翻译、解释必须使用准确的中文。对英语单词，请给出准确的中文对应词义，不要音译。' },
 110→          { role: 'user', content: prompt }
 111→        ]
 112→      };
 113→      if (temperature !== undefined) bodyObj.temperature = temperature;
 114→      body = JSON.stringify(bodyObj);
 115→      headers = {
 116→        'Content-Type': 'application/json',
 117→        'Authorization': 'Bearer ' + cfg.apiKey
 118→      };
 119→    }
 120→
 121→    const opts = {
 122→      hostname: urlObj.hostname, port: urlObj.port || (isHttps ? 443 : 80),
 123→      path: urlObj.pathname, method: 'POST', headers
 124→    };
 125→
 126→    const client = isHttps ? https : http;
 127→    const req = client.request(opts, (res) => {
 128→      let data = '';
 129→      res.on('data', d => data += d);
 130→      res.on('end', () => {
 131→        try {
 132→          const json = JSON.parse(data);
 133→          if (isClaude) {
 134→            resolve(json.content?.[0]?.text || null);
 135→          } else {
 136→            resolve(json.choices?.[0]?.message?.content || null);
 137→          }
 138→        } catch(e) { resolve(null); }
 139→      });
 140→    });
 141→    req.on('error', () => resolve(null));
 142→    req.setTimeout(15000, () => { req.destroy(); resolve(null); });
 143→    req.write(body);
 144→    req.end();
 145→  });
 146→}
 147→
 148→const LANGUAGES = {
 149→  en: { name: '英语', sub: 'en', tts: 'en-US' },
 150→  ja: { name: '日语', sub: 'ja', tts: 'ja-JP' },
 151→  ko: { name: '韩语', sub: 'ko', tts: 'ko-KR' },
 152→  ru: { name: '俄语', sub: 'ru', tts: 'ru-RU' },
 153→  th: { name: '泰语', sub: 'th', tts: 'th-TH' },
 154→  vi: { name: '越南语', sub: 'vi', tts: 'vi-VN' },
 155→  ms: { name: '马来语', sub: 'ms', tts: 'ms-MY' },
 156→  id: { name: '印尼语', sub: 'id', tts: 'id-ID' },
 157→  ar: { name: '阿拉伯语', sub: 'ar', tts: 'ar-SA' },
 158→  pt: { name: '葡萄牙语', sub: 'pt', tts: 'pt-BR' },
 159→  es: { name: '西班牙语', sub: 'es', tts: 'es-ES' },
 160→  fr: { name: '法语', sub: 'fr', tts: 'fr-FR' },
 161→  de: { name: '德语', sub: 'de', tts: 'de-DE' },
 162→  hi: { name: '印地语', sub: 'hi', tts: 'hi-IN' }
 163→};
 164→
 165→function initDB() {
 166→  const dbPath = path.join(__dirname, 'stardict.db');
 167→  if (fs.existsSync(dbPath)) {
 168→    try {
 169→      const Database = require('better-sqlite3');
 170→      db = new Database(dbPath, { readonly: true });
 171→      db.pragma('journal_mode = WAL');
 172→    } catch (e) { console.error('ECDICT加载失败:', e.message); }
 173→  }
 174→}
 175→
 176→function initUserDB() {
 177→  try {
 178→    const Database = require('better-sqlite3');
 179→    userDb = new Database(path.join(USER_DATA, 'userdata.db'));
 180→    userDb.pragma('journal_mode = WAL');
 181→    userDb.exec(`CREATE TABLE IF NOT EXISTS favorites (
 182→      id INTEGER PRIMARY KEY AUTOINCREMENT,
 183→      word TEXT NOT NULL, lang TEXT NOT NULL DEFAULT 'en',
 184→      phonetic TEXT DEFAULT '', translation TEXT DEFAULT '',
 185→      context TEXT DEFAULT '', created_at INTEGER NOT NULL,
 186→      box TEXT DEFAULT ''
 187→    )`);
 188→    userDb.exec(`CREATE UNIQUE INDEX IF NOT EXISTS idx_fav_word_lang ON favorites(word, lang)`);
 189→    // 兼容旧表：添加 box 列
 190→    try { userDb.exec(`ALTER TABLE favorites ADD COLUMN box TEXT DEFAULT ''`); } catch(e) {}
 191→  } catch (e) { console.error('UserDB初始化失败:', e.message); }
 192→}
 193→
 194→function createWindow() {
 195→  mainWindow = new BrowserWindow({
 196→    width: 1100, height: 850, minWidth: 900, minHeight: 700,
 197→    backgroundColor: '#0a0a1a',
 198→    webPreferences: { nodeIntegration: true, contextIsolation: false, webSecurity: false, zoomFactor: 1.0 }
 199→  });
 200→  mainWindow.loadFile('index.html');
 201→  // 允许 Ctrl+滚轮缩放
 202→  mainWindow.webContents.on('zoom-changed', (_, dir) => {
 203→    const cur = mainWindow.webContents.getZoomLevel();
 204→    mainWindow.webContents.setZoomLevel(cur + (dir === 'in' ? 0.5 : -0.5));
 205→  });
 206→}
 207→
 208→app.whenReady().then(() => {
 209→  initDB();
 210→  initUserDB();
 211→  if (!fs.existsSync(DOWNLOADS)) fs.mkdirSync(DOWNLOADS, { recursive: true });
 212→  createWindow();
 213→});
 214→app.on('window-all-closed', () => { if (process.platform !== 'darwin') app.quit(); });
 215→
 216→// ===== IPC =====
 217→
 218→ipcMain.handle('get-languages', () => LANGUAGES);
 219→ipcMain.handle('get-ai-providers', () => AI_PROVIDERS);
 220→ipcMain.handle('get-ai-config', () => loadAIConfig());
 221→ipcMain.handle('save-ai-config', (_, cfg) => { saveAIConfig(cfg); return true; });
 222→ipcMain.handle('set-current-lang', (_, lang) => { currentLangGlobal = lang; });
 223→ipcMain.handle('test-ai-connection', async (_, cfg) => {
 224→  try {
 225→    // 临时保存配置再测试
 226→    saveAIConfig(cfg);
 227→    const result = await callAI('请回复"连接成功"四个字');
 228→    if (result) return { success: true, message: result.slice(0, 100) };
 229→    return { success: false, message: 'API 无响应，请检查 Key 和服务商设置' };
 230→  } catch(e) { return { success: false, message: e.message }; }
 231→});
 232→
 233→// 下载视频+字幕
 234→ipcMain.handle('download-video', async (_, url, lang) => {
 235→  const subLang = LANGUAGES[lang]?.sub || 'en';
 236→  return new Promise((resolve) => {
 237→    const infoArgs = ['--dump-json', '--no-playlist', url];
 238→    if (fs.existsSync(path.join(FFMPEG_DIR, 'ffmpeg.exe'))) infoArgs.unshift('--ffmpeg-location', FFMPEG_DIR);
 239→    const infoProc = spawn(YTDLP, infoArgs);
 240→    let infoOut = '';
 241→    infoProc.stdout.on('data', d => infoOut += d);
 242→    infoProc.on('close', (code) => {
 243→      let title = 'video_' + Date.now();
 244→      if (code === 0) { try { title = JSON.parse(infoOut).title || title; } catch(e) {} }
 245→      const safeName = title.replace(/[<>:"/\\|?*]/g, '_').substring(0, 60);
 246→      const outTemplate = path.join(DOWNLOADS, safeName + '.%(ext)s');
 247→      const args = [
 248→        '--ffmpeg-location', FFMPEG_DIR,
 249→        '-f', 'bestvideo[height<=720]+bestaudio/best[height<=720]/best',
 250→        '--merge-output-format', 'mp4',
 251→        '--write-sub', '--write-auto-sub', '--sub-lang', subLang,
 252→        '--sub-format', 'vtt', '--convert-subs', 'vtt',
 253→        '--no-playlist', '-o', outTemplate, url
 254→      ];
 255→      const proc = spawn(YTDLP, args);
 256→      let stderr = '', maxPercent = 0, streamCount = 0;
 257→      proc.stdout.on('data', (data) => {
 258→        const output = data.toString();
 259→        if (output.includes('Destination:')) streamCount++;
 260→        const matches = output.match(/(\d+\.?\d*)%/g);
 261→        if (matches) {
 262→          let percent = parseFloat(matches[matches.length - 1]);
 263→          if (streamCount >= 2) percent = 50 + percent / 2;
 264→          else if (streamCount === 1) percent = percent / 2;
 265→          if (percent > maxPercent) { maxPercent = percent; mainWindow.webContents.send('download-progress', { percent }); }
 266→        }
 267→        if (output.includes('Merging')) mainWindow.webContents.send('download-progress', { percent: 99 });
 268→      });
 269→      proc.stderr.on('data', d => stderr += d);
 270→      proc.on('close', (code2) => {
 271→        if (code2 !== 0) { resolve({ success: false, error: stderr || '下载失败' }); return; }
 272→        const videoFile = path.join(DOWNLOADS, safeName + '.mp4');
 273→        let subFile = null;
 274→        const possibleSubs = [
 275→          path.join(DOWNLOADS, safeName + '.' + subLang + '.vtt'),
 276→          path.join(DOWNLOADS, safeName + '.vtt'),
 277→        ];
 278→        try {
 279→          for (const f of fs.readdirSync(DOWNLOADS)) {
 280→            if (f.startsWith(safeName) && f.endsWith('.vtt')) possibleSubs.push(path.join(DOWNLOADS, f));
 281→          }
 282→        } catch(e) {}
 283→        for (const p of possibleSubs) { if (fs.existsSync(p)) { subFile = p; break; } }
 284→        resolve({ success: true, videoPath: fs.existsSync(videoFile) ? videoFile : null, subtitlePath: subFile, title: safeName });
 285→      });
 286→      proc.on('error', () => resolve({ success: false, error: 'yt-dlp未找到' }));
 287→    });
 288→  });
 289→});
 290→
 291→// ECDICT查词
 292→ipcMain.handle('lookup-word', (_, word) => {
 293→  if (!db) return null;
 294→  try {
 295→    return db.prepare('SELECT word, phonetic, translation, exchange FROM stardict WHERE word = ? COLLATE NOCASE').get(word.toLowerCase().trim()) || null;
 296→  } catch(e) { return null; }
 297→});
 298→
 299→// 在线翻译
 300→ipcMain.handle('translate-word', (_, word, fromLang) => {
 301→  return new Promise((resolve) => {
 302→    const url = `https://api.mymemory.translated.net/get?q=${encodeURIComponent(word)}&langpair=${fromLang}|zh`;
 303→    https.get(url, (res) => {
 304→      let data = '';
 305→      res.on('data', d => data += d);
 306→      res.on('end', () => {
 307→        try {
 308→          const json = JSON.parse(data);
 309→          resolve({
 310→            translation: json.responseData?.translatedText || null,
 311→            matches: (json.matches || []).slice(0, 3).map(m => ({ segment: m.segment, translation: m.translation }))
 312→          });
 313→        } catch(e) { resolve(null); }
 314→      });
 315→    }).on('error', () => resolve(null));
 316→  });
 317→});
 318→
 319→// 在线例句 (多语种)
 320→ipcMain.handle('fetch-examples', (_, word, lang) => {
 321→  if (lang === 'ja') {
 322→    // 日语: jisho.org API
 323→    return new Promise((resolve) => {
 324→      const url = `https://jisho.org/api/v1/search/words?keyword=${encodeURIComponent(word)}`;
 325→      https.get(url, (res) => {
 326→        let data = '';
 327→        res.on('data', d => data += d);
 328→        res.on('end', () => {
 329→          try {
 330→            const json = JSON.parse(data);
 331→            const entry = json.data?.[0];
 332→            if (!entry) { resolve(null); return; }
 333→            const reading = entry.japanese?.[0]?.reading || '';
 334→            const definitions = (entry.senses || []).slice(0, 5).map(s => ({
 335→              partOfSpeech: (s.parts_of_speech || []).join(', '),
 336→              definition: (s.english_definitions || []).join('; ')
 337→            }));
 338→            resolve({ phonetic: reading, definitions, examples: [] });
 339→          } catch(e) { resolve(null); }
 340→        });
 341→      }).on('error', () => resolve(null));
 342→    });
 343→  }
 344→  // 英语: dictionaryapi.dev
 345→  return new Promise((resolve) => {
 346→    const apiLang = lang === 'en' || !lang ? 'en' : lang;
 347→    const url = `https://api.dictionaryapi.dev/api/v2/entries/${apiLang}/${encodeURIComponent(word)}`;
 348→    https.get(url, (res) => {
 349→      let data = '';
 350→      res.on('data', d => data += d);
 351→      res.on('end', () => {
 352→        try {
 353→          const json = JSON.parse(data);
 354→          if (!Array.isArray(json)) { resolve(null); return; }
 355→          const entry = json[0], examples = [], definitions = [];
 356→          for (const meaning of (entry.meanings || [])) {
 357→            for (const def of (meaning.definitions || [])) {
 358→              definitions.push({ partOfSpeech: meaning.partOfSpeech, definition: def.definition });
 359→              if (def.example) examples.push(def.example);
 360→            }
 361→          }
 362→          resolve({
 363→            phonetic: entry.phonetic || '',
 364→            audio: entry.phonetics?.find(p => p.audio)?.audio || '',
 365→            definitions: definitions.slice(0, 5),
 366→            examples: examples.slice(0, 5)
 367→          });
 368→        } catch(e) { resolve(null); }
 369→      });
 370→    }).on('error', () => resolve(null));
 371→  });
 372→});
