 509→function generateImageDalle(cfg, prompt) {
 510→  return new Promise((resolve) => {
 511→    const baseUrl = cfg.provider === 'openai' ? 'https://api.openai.com/v1' : (cfg.baseUrl || 'https://api.openai.com/v1');
 512→    // 非OpenAI供应商若无图片能力则回退
 513→    const urlObj = new URL(baseUrl + '/images/generations');
 514→    const isHttps = urlObj.protocol === 'https:';
 515→    const body = JSON.stringify({ model: 'dall-e-3', prompt, n: 1, size: '1024x1024', response_format: 'b64_json' });
 516→    const opts = {
 517→      hostname: urlObj.hostname, port: urlObj.port || (isHttps ? 443 : 80),
 518→      path: urlObj.pathname, method: 'POST',
 519→      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + cfg.apiKey }
 520→    };
 521→    const client = isHttps ? https : http;
 522→    const req = client.request(opts, (res) => {
 523→      let data = '';
 524→      res.on('data', d => data += d);
 525→      res.on('end', () => {
 526→        try {
 527→          const json = JSON.parse(data);
 528→          const b64 = json.data?.[0]?.b64_json;
 529→          if (b64) resolve('data:image/png;base64,' + b64);
 530→          else resolve(json.data?.[0]?.url || null);
 531→        } catch(e) { resolve(null); }
 532→      });
 533→    });
 534→    req.on('error', () => resolve(null));
 535→    req.setTimeout(60000, () => { req.destroy(); resolve(null); });
 536→    req.write(body);
 537→    req.end();
 538→  });
 539→}
