 567→function generateImageQwen(apiKey, prompt) {
 568→  return new Promise((resolve) => {
 569→    const body = JSON.stringify({ model: 'wanx-v1', input: { prompt }, parameters: { n: 1, size: '1024*1024' } });
 570→    const opts = {
 571→      hostname: 'dashscope.aliyuncs.com', port: 443,
 572→      path: '/api/v1/services/aigc/text2image/image-synthesis', method: 'POST',
 573→      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey, 'X-DashScope-Async': 'enable' }
 574→    };
 575→    const req = https.request(opts, (res) => {
 576→      let data = '';
 577→      res.on('data', d => data += d);
 578→      res.on('end', async () => {
 579→        try {
 580→          const json = JSON.parse(data);
 581→          const taskId = json.output?.task_id;
 582→          if (!taskId) { resolve(null); return; }
 583→          // 轮询等待结果
 584→          for (let i = 0; i < 30; i++) {
 585→            await new Promise(r => setTimeout(r, 2000));
 586→            const result = await qwenCheckTask(apiKey, taskId);
 587→            if (result) { resolve(result); return; }
 588→          }
 589→          resolve(null);
 590→        } catch(e) { resolve(null); }
 591→      });
 592→    });
 593→    req.on('error', () => resolve(null));
 594→    req.setTimeout(60000, () => { req.destroy(); resolve(null); });
 595→    req.write(body);
 596→    req.end();
 597→  });
 598→}
