 600→function qwenCheckTask(apiKey, taskId) {
 601→  return new Promise((resolve) => {
 602→    const opts = {
 603→      hostname: 'dashscope.aliyuncs.com', port: 443,
 604→      path: '/api/v1/tasks/' + taskId, method: 'GET',
 605→      headers: { 'Authorization': 'Bearer ' + apiKey }
 606→    };
 607→    const req = https.request(opts, (res) => {
 608→      let data = '';
 609→      res.on('data', d => data += d);
 610→      res.on('end', () => {
 611→        try {
 612→          const json = JSON.parse(data);
 613→          if (json.output?.task_status === 'SUCCEEDED') {
 614→            resolve(json.output.results?.[0]?.url || null);
 615→          } else if (json.output?.task_status === 'FAILED') { resolve(null); }
 616→          else resolve(null); // still running, return null to keep polling
 617→        } catch(e) { resolve(null); }
 618→      });
 619→    });
 620→    req.on('error', () => resolve(null));
 621→    req.end();
 622→  });
 623→}
