function generateImageDalle(cfg, prompt) {
  return new Promise((resolve) => {
    const baseUrl = cfg.provider === 'openai' ? 'https://api.openai.com/v1' : (cfg.baseUrl || 'https://api.openai.com/v1');
    // 非OpenAI供应商若无图片能力则回退
    const urlObj = new URL(baseUrl + '/images/generations');
    const isHttps = urlObj.protocol === 'https:';
    const body = JSON.stringify({ model: 'dall-e-3', prompt, n: 1, size: '1024x1024', response_format: 'b64_json' });
    const opts = {
      hostname: urlObj.hostname, port: urlObj.port || (isHttps ? 443 : 80),
      path: urlObj.pathname, method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + cfg.apiKey }
    };
    const client = isHttps ? https : http;
    const req = client.request(opts, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          const b64 = json.data?.[0]?.b64_json;
