document.getElementById('lawModalClose').addEventListener('click', () => lawModal.classList.remove('show'));
lawModal.addEventListener('click', (e) => { if (e.target === lawModal) lawModal.classList.remove('show'); });

let regulationsData = null;
let currentLawCountry = null;

async function loadRegulations(forceReload) {
  if (forceReload) regulationsData = null;
  if (!regulationsData) regulationsData = await ipcRenderer.invoke('get-regulations');
  const btns = document.getElementById('lawCountryBtns');
  btns.innerHTML = '';
  for (const [code, country] of Object.entries(regulationsData)) {
    const btn = document.createElement('button');
    btn.className = 'law-country-btn';
    btn.textContent = country.name;
    btn.dataset.code = code;
    btn.addEventListener('click', () => {
      btns.querySelectorAll('.law-country-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      currentLawCountry = code;
      showLawItems(code);
    });
    btns.appendChild(btn);
  }
  // + 添加国家按钮
  const addBtn = document.createElement('button');
  addBtn.className = 'law-country-btn';
  addBtn.textContent = '＋ 添加';
  addBtn.style.borderStyle = 'dashed';
  addBtn.addEventListener('click', showAddCountryForm);
  btns.appendChild(addBtn);
  // 选中之前的或第一个
  const target = currentLawCountry ? btns.querySelector(`[data-code="${currentLawCountry}"]`) : btns.querySelector('.law-country-btn');
  if (target && target !== addBtn) target.click();
  else if (btns.children.length > 1) btns.children[0].click();
}

function showAddCountryForm() {
  const container = document.getElementById('lawItems');
  container.innerHTML = `<div class="law-item" style="padding:16px">
    <div style="margin-bottom:8px;font-weight:bold;color:var(--accent)">添加新国家/地区</div>
    <input id="newCountryCode" placeholder="代码 (如 sg, uk)" style="width:100%;padding:6px 10px;margin-bottom:6px;background:var(--input-bg);border:1px solid var(--input-border);border-radius:6px;color:var(--text);font-size:13px">
    <input id="newCountryName" placeholder="名称 (如 新加坡)" style="width:100%;padding:6px 10px;margin-bottom:6px;background:var(--input-bg);border:1px solid var(--input-border);border-radius:6px;color:var(--text);font-size:13px">
    <select id="newCountryLang" style="width:100%;padding:6px 10px;margin-bottom:10px;background:var(--input-bg);border:1px solid var(--input-border);border-radius:6px;color:var(--text);font-size:13px">
      <option value="zh-CN">中文</option><option value="en-US">英语</option><option value="ja-JP">日语</option>
      <option value="ko-KR">韩语</option><option value="ru-RU">俄语</option><option value="fr-FR">法语</option>
      <option value="de-DE">德语</option><option value="es-ES">西班牙语</option><option value="pt-BR">葡萄牙语</option>
      <option value="ar-SA">阿拉伯语</option><option value="th-TH">泰语</option><option value="vi-VN">越南语</option>
      <option value="ms-MY">马来语</option><option value="id-ID">印尼语</option><option value="hi-IN">印地语</option>
    </select>
    <button id="saveNewCountry" class="btn btn-small" style="background:var(--btn-primary)">保存</button>
  </div>`;
  document.getElementById('saveNewCountry').addEventListener('click', async () => {
    const code = document.getElementById('newCountryCode').value.trim().toLowerCase();
    const name = document.getElementById('newCountryName').value.trim();
    const lang = document.getElementById('newCountryLang').value;
    if (!code || !name) return;
    // 添加一条占位法规以创建国家
    await ipcRenderer.invoke('reg-add-item', code, name, lang, name + ' - 示例条目', '请编辑此条目或添加新法规。');
    currentLawCountry = code;
    await loadRegulations(true);
  });
}

function showLawItems(countryCode) {
  const country = regulationsData[countryCode];
  const container = document.getElementById('lawItems');
  container.innerHTML = '';
  for (const item of country.items) {
    const div = document.createElement('div');
    div.className = 'law-item';
    const delHtml = item._user ? `<button class="law-del-btn" title="删除">✕</button>` : '';
    div.innerHTML = `<div class="law-item-title">${item.title} <button class="law-speak-btn">🔊</button>${delHtml}</div>
      <div class="law-item-content">${item.content}</div>`;
    div.querySelector('.law-speak-btn').addEventListener('click', () => {
      speechSynthesis.cancel();
      const u = new SpeechSynthesisUtterance(item.content);
      u.lang = country.lang; u.rate = 0.85;
      speechSynthesis.speak(u);
    });
    if (item._user) {
      div.querySelector('.law-del-btn').addEventListener('click', async () => {
        await ipcRenderer.invoke('reg-delete-item', item.id);
        await loadRegulations(true);
      });
    }
    container.appendChild(div);
  }
  // 添加条目按钮
  const addDiv = document.createElement('div');
  addDiv.className = 'law-item';
  addDiv.style.cssText = 'border-style:dashed;cursor:pointer;text-align:center;color:var(--text-dim)';
  addDiv.textContent = '＋ 添加法规条目';
  addDiv.addEventListener('click', () => showAddItemForm(countryCode, country));
  container.appendChild(addDiv);
}

function showAddItemForm(countryCode, country) {
  const container = document.getElementById('lawItems');
  const form = document.createElement('div');
  form.className = 'law-item';
  form.style.padding = '16px';
  form.innerHTML = `<input id="newItemTitle" placeholder="标题 (如 民法典 第三条)" style="width:100%;padding:6px 10px;margin-bottom:6px;background:var(--input-bg);border:1px solid var(--input-border);border-radius:6px;color:var(--text);font-size:13px">
    <textarea id="newItemContent" placeholder="法规内容" rows="3" style="width:100%;padding:6px 10px;margin-bottom:10px;background:var(--input-bg);border:1px solid var(--input-border);border-radius:6px;color:var(--text);font-size:13px;resize:vertical"></textarea>
    <button id="saveNewItem" class="btn btn-small" style="background:var(--btn-primary)">保存</button>`;
  container.appendChild(form);
  form.scrollIntoView({ behavior: 'smooth' });
  document.getElementById('saveNewItem').addEventListener('click', async () => {
    const title = document.getElementById('newItemTitle').value.trim();
    const content = document.getElementById('newItemContent').value.trim();
    if (!title || !content) return;
    await ipcRenderer.invoke('reg-add-item', countryCode, country.name, country.lang, title, content);
    await loadRegulations(true);
  });
}

