 252→async function loadVideo(videoPath, subtitlePath) {
 253→  playerArea.style.display = 'block';
 254→  currentVideoPath = videoPath;
 255→  videoPlayer.src = 'file:///' + videoPath.replace(/\\/g, '/');
 256→  subtitles = []; currentSubIndex = -1; wordTimings = null;
 257→  subtitleText.textContent = '加载字幕中...';
 258→  aiAnalyzeBtn.style.display = 'none';
 259→  aiResult.style.display = 'none';
 260→  const subtitleList = document.getElementById('subtitleList');
 261→  subtitleList.innerHTML = '';
 262→
 263→  let loaded = false;
 264→  // 优先尝试传入的字幕路径
 265→  if (subtitlePath) {
 266→    const vtt = await ipcRenderer.invoke('read-subtitle', subtitlePath);
 267→    if (vtt) {
 268→      subtitles = parseVTT(vtt);
 269→      if (subtitles.length > 0) {
 270→        buildSubtitleList();
 271→        subtitleText.textContent = `已加载 ${subtitles.length} 条字幕，播放视频即可同步显示`;
 272→        loaded = true;
 273→      }
 274→    }
 275→  }
 276→  // 没有传入字幕时，先检查同名.vtt是否已存在（之前转录过的）
 277→  if (!loaded) {
 278→    const existingVtt = await ipcRenderer.invoke('check-existing-subtitle', videoPath);
 279→    if (existingVtt) {
 280→      const vtt = await ipcRenderer.invoke('read-subtitle', existingVtt);
 281→      if (vtt) {
 282→        subtitles = parseVTT(vtt);
 283→        if (subtitles.length > 0) {
 284→          buildSubtitleList();
 285→          subtitleText.textContent = `已加载 ${subtitles.length} 条字幕，播放视频即可同步显示`;
 286→          loaded = true;
 287→        }
 288→      }
 289→    }
 290→  }
 291→  // 都没有才启动语音识别
 292→  if (!loaded) {
 293→    subtitleText.textContent = '无字幕文件，正在启动语音识别...';
 294→    const vttPath = await ipcRenderer.invoke('generate-subtitle', videoPath);
 295→    if (vttPath) {
 296→      const vtt = await ipcRenderer.invoke('read-subtitle', vttPath);
 297→      if (vtt) {
 298→        subtitles = parseVTT(vtt);
 299→        if (subtitles.length > 0) {
 300→          buildSubtitleList();
 301→          subtitleText.textContent = `语音识别完成，已生成 ${subtitles.length} 条字幕`;
 302→          loaded = true;
 303→        }
 304→      }
 305→    }
 306→    if (!loaded) subtitleText.textContent = '语音识别失败，请确认 funasr 服务已启动';
 307→  }
 308→  // 加载逐词时间戳（如果有）
 309→  const vttFile = subtitlePath || await ipcRenderer.invoke('check-existing-subtitle', videoPath);
 310→  if (vttFile) wordTimings = await ipcRenderer.invoke('read-word-timestamps', vttFile);
 311→}
 312→
 313→// VTT解析 (处理YouTube自动字幕的双行格式)
 314→function parseVTT(vtt) {
 315→  const raw = [];
 316→  for (const block of vtt.split(/\n\n+/)) {
 317→    const lines = block.trim().split('\n');
 318→    for (let i = 0; i < lines.length; i++) {
 319→      const m = lines[i].match(/(\d{2}):(\d{2}):(\d{2})\.(\d{3})\s*-->\s*(\d{2}):(\d{2}):(\d{2})\.(\d{3})/);
 320→      if (!m) continue;
 321→      const start = +m[1]*3600 + +m[2]*60 + +m[3] + +m[4]/1000;
 322→      const end = +m[5]*3600 + +m[6]*60 + +m[7] + +m[8]/1000;
 323→      // 跳过极短条目(YouTube自动字幕的过渡帧)
 324→      if (end - start < 0.05) break;
 325→      // 取最后一行非空文本(YouTube双行字幕中新内容在最后一行)
 326→      const textLines = lines.slice(i+1).map(l => l.replace(/<[^>]+>/g, '').trim()).filter(Boolean);
 327→      const text = textLines.length > 0 ? textLines[textLines.length - 1] : '';
 328→      if (text) raw.push({ start, end, text });
 329→      break;
 330→    }
 331→  }
 332→  // 合并连续相同文本，去重
 333→  const result = [];
 334→  for (const s of raw) {
 335→    if (result.length > 0 && result[result.length-1].text === s.text) {
 336→      result[result.length-1].end = s.end; // 延长时间
 337→    } else {
 338→      result.push({ ...s });
 339→    }
 340→  }
 341→  return result;
 342→}
 343→
 344→// 字幕同步 (用setInterval确保可靠触发)
 345→let syncTimer = null;
 346→function startSubtitleSync() {
 347→  if (syncTimer) clearInterval(syncTimer);
 348→  syncTimer = setInterval(() => {
 349→    if (!subtitles.length || currentMode !== 'learn' || videoPlayer.paused) return;
 350→    const t = videoPlayer.currentTime;
 351→    // 二分查找当前时间对应的字幕
 352→    let lo = 0, hi = subtitles.length - 1, idx = -1;
 353→    while (lo <= hi) {
 354→      const mid = (lo + hi) >> 1;
 355→      if (t >= subtitles[mid].start && t <= subtitles[mid].end) { idx = mid; break; }
 356→      if (t < subtitles[mid].start) hi = mid - 1;
 357→      else lo = mid + 1;
 358→    }
 359→    if (idx < 0) {
 360→      // 在间隙中：找下一条即将出现的字幕（0.5秒内），或保持上一条
 361→      for (let i = 0; i < subtitles.length; i++) {
 362→        if (subtitles[i].start > t) {
 363→          if (subtitles[i].start - t < 0.5) { idx = i; }
 364→          else if (i > 0) { idx = i - 1; }
 365→          break;
 366→        }
 367→      }
 368→      if (idx < 0) idx = subtitles.length - 1; // 超过最后一条
 369→    }
 370→    if (idx !== currentSubIndex) {
 371→      currentSubIndex = idx;
 372→      currentSentence = subtitles[idx].text;
 373→      renderSubtitle(currentSentence);
 374→      aiAnalyzeBtn.style.display = 'inline-block';
 375→      aiResult.style.display = 'none';
 376→      highlightSubtitleList(idx);
 377→    }
 378→    // 卡拉OK式逐词点亮
 379→    if (idx >= 0 && idx === currentSubIndex) {
 380→      const sub = subtitles[idx];
 381→      const words = subtitleText.querySelectorAll('.word');
 382→      if (words.length > 0) {
 383→        if (wordTimings) {
 384→          // 精准模式：用逐词时间戳
 385→          const subWords = wordTimings.filter(wt => wt.s >= sub.start - 0.05 && wt.e <= sub.end + 0.5);
 386→          if (subWords.length > 0) {
 387→            words.forEach((w, i) => {
 388→              const wt = subWords[i];
 389→              if (wt) {
 390→                w.classList.toggle('word-lit', t >= wt.s && t < wt.e);
 391→                w.classList.toggle('word-past', t >= wt.e);
 392→              }
 393→            });
 394→          } else {
 395→            fallbackHighlight(words, t, sub);
 396→          }
 397→        } else {
 398→          fallbackHighlight(words, t, sub);
 399→        }
 400→      }
 401→    }
 402→  }, 50);
 403→}
