 406→function fallbackHighlight(words, t, sub) {
 407→  const elapsed = t - sub.start;
 408→  const dur = sub.end - sub.start;
 409→  if (dur <= 0 || elapsed < 0) return;
 410→  const lens = Array.from(words).map(w => Math.max(w.textContent.length, 1));
 411→  const total = lens.reduce((a, b) => a + b, 0);
 412→  let cum = 0, activeIdx = words.length - 1;
 413→  for (let i = 0; i < lens.length; i++) {
 414→    cum += (lens[i] / total) * dur;
 415→    if (elapsed < cum) { activeIdx = i; break; }
 416→  }
 417→  words.forEach((w, i) => {
 418→    w.classList.toggle('word-lit', i === activeIdx);
 419→    w.classList.toggle('word-past', i < activeIdx);
 420→  });
 421→}
