1161→function drawFallbackBg(ctx, W, H, title) {
1162→  // 丰富的渐变背景
1163→  const colors = [
1164→    ['#667eea', '#764ba2'], ['#f093fb', '#f5576c'], ['#4facfe', '#00f2fe'],
1165→    ['#43e97b', '#38f9d7'], ['#fa709a', '#fee140'], ['#a18cd1', '#fbc2eb']
1166→  ];
1167→  const pair = colors[Math.abs(title.charCodeAt(0)) % colors.length];
1168→  const grad = ctx.createLinearGradient(0, 0, W, H);
1169→  grad.addColorStop(0, pair[0]); grad.addColorStop(1, pair[1]);
1170→  ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);
1171→
1172→  // 装饰元素 - 大圆、小圆、波浪
1173→  ctx.globalAlpha = 0.12;
1174→  for (let i = 0; i < 8; i++) {
1175→    const cx = Math.random() * W, cy = Math.random() * H * 0.7, r = 40 + Math.random() * 100;
1176→    ctx.fillStyle = '#fff';
1177→    ctx.beginPath(); ctx.arc(cx, cy, r, 0, Math.PI * 2); ctx.fill();
1178→  }
1179→  // 底部波浪
1180→  ctx.fillStyle = 'rgba(255,255,255,0.15)';
1181→  ctx.beginPath(); ctx.moveTo(0, H * 0.65);
1182→  for (let x = 0; x <= W; x += 20) {
1183→    ctx.lineTo(x, H * 0.65 + Math.sin(x * 0.015) * 30 + Math.sin(x * 0.008) * 20);
1184→  }
1185→  ctx.lineTo(W, H); ctx.lineTo(0, H); ctx.fill();
1186→  ctx.globalAlpha = 1;
1187→}
1188→
1189→function rrect(ctx, x, y, w, h, r) {
1190→  ctx.beginPath(); ctx.moveTo(x + r, y); ctx.lineTo(x + w - r, y);
1191→  ctx.quadraticCurveTo(x + w, y, x + w, y + r); ctx.lineTo(x + w, y + h - r);
1192→  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h); ctx.lineTo(x + r, y + h);
1193→  ctx.quadraticCurveTo(x, y + h, x, y + h - r); ctx.lineTo(x, y + r);
1194→  ctx.quadraticCurveTo(x, y, x + r, y); ctx.closePath();
1195→}
