1235→function speakLecture(text) {
1236→  speechSynthesis.cancel();
1237→  // 分段朗读，每段不超过200字
1238→  const chunks = [];
1239→  let remaining = text;
1240→  while (remaining.length > 0) {
1241→    if (remaining.length <= 200) { chunks.push(remaining); break; }
1242→    let cut = remaining.lastIndexOf('。', 200);
1243→    if (cut < 50) cut = remaining.lastIndexOf('.', 200);
1244→    if (cut < 50) cut = remaining.lastIndexOf('，', 200);
1245→    if (cut < 50) cut = 200;
1246→    chunks.push(remaining.slice(0, cut + 1));
1247→    remaining = remaining.slice(cut + 1);
1248→  }
1249→  let i = 0;
1250→  function next() {
1251→    if (i >= chunks.length) return;
1252→    const u = new SpeechSynthesisUtterance(chunks[i]);
1253→    u.lang = 'zh-CN'; u.rate = 0.9;
1254→    u.onend = () => { i++; next(); };
1255→    speechSynthesis.speak(u);
1256→  }
1257→  next();
1258→}
