document.getElementById('retranscribeBtn').addEventListener('click', async () => {
  if (!currentVideoPath) return;
  videoPlayer.pause();
  await ipcRenderer.invoke('delete-subtitle', currentVideoPath);
  subtitles = []; currentSubIndex = -1; wordTimings = null;
  subtitleText.textContent = '正在重新转录...';
  document.getElementById('subtitleList').innerHTML = '';

