function generateImageDalle(cfg, prompt) {
  return new Promise((resolve) => {
    const baseUrl = cfg.provider === 'openai' ? 'https://api.openai.com/v1' : (cfg.baseUrl || 'https://api.openai.com/v1');
    // 非OpenAI供应商若无图片能力则回退
    const urlObj = new URL(baseUrl + '/images/generations');
    const isHttps = urlObj.protocol === 'https:';
    const body = JSON.stringify({ model: 'dall-e-3', prompt, n: 1, size: '1024x1024', response_format: 'b64_json' });
    const opts = {
      hostname: urlObj.hostname, port: urlObj.port || (isHttps ? 443 : 80),
      path: urlObj.pathname, method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + cfg.apiKey }
    };
    const client = isHttps ? https : http;
    const req = client.request(opts, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          const b64 = json.data?.[0]?.b64_json;
          if (b64) resolve('data:image/png;base64,' + b64);
          else resolve(json.data?.[0]?.url || null);
        } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(60000, () => { req.destroy(); resolve(null); });
    req.write(body);
    req.end();
  });
}

function generateImageZhipu(apiKey, prompt) {
  return new Promise((resolve) => {
    const body = JSON.stringify({ model: 'cogview-3-plus', prompt });
    const opts = {
      hostname: 'open.bigmodel.cn', port: 443,
      path: '/api/paas/v4/images/generations', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey }
    };
    const req = https.request(opts, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          console.log('Zhipu image response:', JSON.stringify(json).slice(0, 200));
          resolve(json.data?.[0]?.url || null);
        } catch(e) { console.error('Zhipu image parse error:', e.message); resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(60000, () => { req.destroy(); resolve(null); });
    req.write(body);
    req.end();
  });
}

function generateImageQwen(apiKey, prompt) {
  return new Promise((resolve) => {
    const body = JSON.stringify({ model: 'wanx-v1', input: { prompt }, parameters: { n: 1, size: '1024*1024' } });
    const opts = {
      hostname: 'dashscope.aliyuncs.com', port: 443,
      path: '/api/v1/services/aigc/text2image/image-synthesis', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey, 'X-DashScope-Async': 'enable' }
    };
    const req = https.request(opts, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', async () => {
        try {
          const json = JSON.parse(data);
          const taskId = json.output?.task_id;
          if (!taskId) { resolve(null); return; }
          // 轮询等待结果
          for (let i = 0; i < 30; i++) {
            await new Promise(r => setTimeout(r, 2000));
            const result = await qwenCheckTask(apiKey, taskId);
            if (result) { resolve(result); return; }
          }
          resolve(null);
        } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.setTimeout(60000, () => { req.destroy(); resolve(null); });
    req.write(body);
    req.end();
  });
}

function qwenCheckTask(apiKey, taskId) {
  return new Promise((resolve) => {
    const opts = {
      hostname: 'dashscope.aliyuncs.com', port: 443,
      path: '/api/v1/tasks/' + taskId, method: 'GET',
      headers: { 'Authorization': 'Bearer ' + apiKey }
    };
    const req = https.request(opts, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.output?.task_status === 'SUCCEEDED') {
            resolve(json.output.results?.[0]?.url || null);
          } else if (json.output?.task_status === 'FAILED') { resolve(null); }
          else resolve(null); // still running, return null to keep polling
        } catch(e) { resolve(null); }
      });
    });
    req.on('error', () => resolve(null));
    req.end();
  });
}

