if (idx >= 0 && idx === currentSubIndex) {
  const sub = subtitles[idx];
  const words = subtitleText.querySelectorAll('.word');
  if (words.length > 0) {
    if (wordTimings) {
      // 精准模式：用逐词时间戳，按文本匹配对齐
      const subWords = wordTimings.filter(wt => wt.s >= sub.start - 0.1 && wt.s <= sub.end + 0.3);
      if (subWords.length > 0) {
        // 建立显示词 → wordTiming 的精准映射
        let wtIdx = 0;
        words.forEach((w) => {
          const displayed = w.textContent.trim().toLowerCase().replace(/[^\p{L}\p{M}\p{N}'-]/gu, '');
          // 向前搜索匹配的 wordTiming
          let matched = null;
          for (let k = wtIdx; k < subWords.length; k++) {
            const wtWord = subWords[k].w.trim().toLowerCase().replace(/[^\p{L}\p{M}\p{N}'-]/gu, '');
            if (wtWord === displayed || displayed.startsWith(wtWord) || wtWord.startsWith(displayed)) {
              matched = subWords[k];
              wtIdx = k + 1;
              break;
            }
          }
          if (matched) {
            w.classList.toggle('word-lit', t >= matched.s && t < matched.e);
            w.classList.toggle('word-past', t >= matched.e);
          } else {
            // 无匹配时不高亮
            w.classList.remove('word-lit', 'word-past');
          }
        });
      } else {
        fallbackHighlight(words, t, sub);
      }
    } else {
      fallbackHighlight(words, t, sub);
    }
  }
}

