  if (vttFile) wordTimings = await ipcRenderer.invoke('read-word-timestamps', vttFile);
}

// VTT解析 (处理YouTube自动字幕的双行格式)
function parseVTT(vtt) {
  const raw = [];
  for (const block of vtt.split(/\n\n+/)) {
    const lines = block.trim().split('\n');
    for (let i = 0; i < lines.length; i++) {
      const m = lines[i].match(/(\d{2}):(\d{2}):(\d{2})\.(\d{3})\s*-->\s*(\d{2}):(\d{2}):(\d{2})\.(\d{3})/);
      if (!m) continue;
      const start = +m[1]*3600 + +m[2]*60 + +m[3] + +m[4]/1000;
      const end = +m[5]*3600 + +m[6]*60 + +m[7] + +m[8]/1000;
      // 跳过极短条目(YouTube自动字幕的过渡帧)
      if (end - start < 0.05) break;
      // 取最后一行非空文本(YouTube双行字幕中新内容在最后一行)
      const textLines = lines.slice(i+1).map(l => l.replace(/<[^>]+>/g, '').trim()).filter(Boolean);
      const text = textLines.length > 0 ? textLines[textLines.length - 1] : '';
      if (text) raw.push({ start, end, text });
      break;
    }
  }
  // 合并连续相同文本，去重
  const result = [];
  for (const s of raw) {
    if (result.length > 0 && result[result.length-1].text === s.text) {
      result[result.length-1].end = s.end; // 延长时间
    } else {
      result.push({ ...s });
    }
  }
  return result;
}

// 字幕同步 (用setInterval确保可靠触发)
let syncTimer = null;
function startSubtitleSync() {
  if (syncTimer) clearInterval(syncTimer);
  syncTimer = setInterval(() => {
    if (!subtitles.length || currentMode !== 'learn' || videoPlayer.paused) return;
    const t = videoPlayer.currentTime;
    // 二分查找当前时间对应的字幕
    let lo = 0, hi = subtitles.length - 1, idx = -1;
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      if (t >= subtitles[mid].start && t <= subtitles[mid].end) { idx = mid; break; }
      if (t < subtitles[mid].start) hi = mid - 1;
      else lo = mid + 1;
    }
    if (idx < 0) {
      // 在间隙中：找下一条即将出现的字幕（0.5秒内），或保持上一条
      for (let i = 0; i < subtitles.length; i++) {
        if (subtitles[i].start > t) {
          if (subtitles[i].start - t < 0.5) { idx = i; }
          else if (i > 0) { idx = i - 1; }
          break;
        }
      }
      if (idx < 0) idx = subtitles.length - 1; // 超过最后一条
    }
    if (idx !== currentSubIndex) {
      currentSubIndex = idx;
      currentSentence = subtitles[idx].text;
      renderSubtitle(currentSentence);
      aiAnalyzeBtn.style.display = 'inline-block';
      aiResult.style.display = 'none';
      highlightSubtitleList(idx);
    }
    // 卡拉OK式逐词点亮
    if (idx >= 0 && idx === currentSubIndex) {
      const sub = subtitles[idx];
      const words = subtitleText.querySelectorAll('.word');
      if (words.length > 0) {
        if (wordTimings) {
          // 精准模式：用逐词时间戳
          const subWords = wordTimings.filter(wt => wt.s >= sub.start - 0.05 && wt.e <= sub.end + 0.5);
          if (subWords.length > 0) {
            words.forEach((w, i) => {
              const wt = subWords[i];
              if (wt) {
                w.classList.toggle('word-lit', t >= wt.s && t < wt.e);
                w.classList.toggle('word-past', t >= wt.e);
              }
            });
          } else {
            fallbackHighlight(words, t, sub);
          }
        } else {
          fallbackHighlight(words, t, sub);
        }
      }
    }
  }, 50);
}
videoPlayer.addEventListener('play', startSubtitleSync);

function fallbackHighlight(words, t, sub) {
  const elapsed = t - sub.start;
  const dur = sub.end - sub.start;
  if (dur <= 0 || elapsed < 0) return;
  const lens = Array.from(words).map(w => Math.max(w.textContent.length, 1));
  const total = lens.reduce((a, b) => a + b, 0);
  let cum = 0, activeIdx = words.length - 1;
  for (let i = 0; i < lens.length; i++) {
    cum += (lens[i] / total) * dur;
    if (elapsed < cum) { activeIdx = i; break; }
  }
  words.forEach((w, i) => {
    w.classList.toggle('word-lit', i === activeIdx);
    w.classList.toggle('word-past', i < activeIdx);
  });
}
videoPlayer.addEventListener('seeked', () => { currentSubIndex = -1; });

// 重新转录
let currentVideoPath = null;
