    container.appendChild(div);
  }
  // 添加条目按钮
  const addDiv = document.createElement('div');
  addDiv.className = 'law-item';
  addDiv.style.cssText = 'border-style:dashed;cursor:pointer;text-align:center;color:var(--text-dim)';
  addDiv.textContent = '＋ 添加法规条目';
