async function loadVocabList() {
  allVocabList = await ipcRenderer.invoke('fav-list');
  const boxes = await ipcRenderer.invoke('fav-list-boxes');
  selectedWordIds.clear();
  updateSelImageBtn();

  // 渲染箱子标签
  const tabs = document.getElementById('vocabBoxTabs');
  tabs.innerHTML = '';
  const allCount = allVocabList.length;
  const unboxedCount = allVocabList.filter(w => !w.box).length;

  const addTab = (label, box, count) => {
    const tab = document.createElement('span');
    tab.className = 'vocab-box-tab' + (currentBox === box ? ' active' : '');
    tab.innerHTML = `${label}<span class="tab-count">${count}</span>`;
    tab.addEventListener('click', () => { currentBox = box; loadVocabList(); });
    // 拖放目标
    tab.addEventListener('dragover', (e) => { e.preventDefault(); tab.style.transform = 'scale(1.1)'; });
    tab.addEventListener('dragleave', () => { tab.style.transform = ''; });
    tab.addEventListener('drop', async (e) => {
      e.preventDefault(); tab.style.transform = '';
      const wordId = e.dataTransfer.getData('text/plain');
      if (wordId) {
        // 如果有多选，批量移动
        const ids = selectedWordIds.size > 0 ? [...selectedWordIds] : [parseInt(wordId)];
        await ipcRenderer.invoke('fav-batch-set-box', ids, box);
        loadVocabList();
      }
    });
    tabs.appendChild(tab);
  };

  addTab('📋 全部', '', allCount);
  addTab('📥 未分类', '__unboxed__', unboxedCount);
  for (const b of boxes) {
    const cnt = allVocabList.filter(w => w.box === b).length;
    addTab('📦 ' + b, b, cnt);
  }

  // 过滤当前箱子
  let filtered = allVocabList;
  if (currentBox === '__unboxed__') filtered = allVocabList.filter(w => !w.box);
  else if (currentBox) filtered = allVocabList.filter(w => w.box === currentBox);

  const grid = document.getElementById('vocabGrid');
  const empty = document.getElementById('vocabEmpty');
  grid.innerHTML = '';
  empty.style.display = filtered.length ? 'none' : 'block';

  for (const item of filtered) {
    const card = document.createElement('div');
    card.className = 'vocab-card';
    card.draggable = true;
    card.dataset.id = item.id;
    card.innerHTML = `<input type="checkbox" class="vocab-check">
      <div class="vocab-card-word" style="margin-left:22px">${item.word}</div>
      <div class="vocab-card-phonetic">${item.phonetic || ''}</div>
      <div class="vocab-card-trans">${item.translation || ''}</div>
      ${item.box ? '<div style="font-size:10px;color:var(--accent3);margin-top:4px">📦 ' + item.box + '</div>' : ''}
      <button class="vocab-card-del" title="删除">✕</button>`;

    // 拖拽
    card.addEventListener('dragstart', (e) => {
      e.dataTransfer.setData('text/plain', String(item.id));
      card.classList.add('dragging');
    });
    card.addEventListener('dragend', () => card.classList.remove('dragging'));

    // 多选
    const chk = card.querySelector('.vocab-check');
    chk.addEventListener('change', () => {
      if (chk.checked) { selectedWordIds.add(item.id); card.classList.add('selected'); }
      else { selectedWordIds.delete(item.id); card.classList.remove('selected'); }
      updateSelImageBtn();
    });

    card.querySelector('.vocab-card-del').addEventListener('click', async () => {
      await ipcRenderer.invoke('fav-remove', item.word, item.lang);
      loadVocabList();
    });
    card.querySelector('.vocab-card-word').addEventListener('click', () => speak(item.word));
    grid.appendChild(card);
  }
}

