  if (!userDb) return [];
  try {
    if (lang) return userDb.prepare('SELECT * FROM favorites WHERE lang=? ORDER BY created_at DESC').all(lang);
    return userDb.prepare('SELECT * FROM favorites ORDER BY created_at DESC').all();
  } catch(e) { return []; }
});
ipcMain.handle('fav-import', (_, words, lang) => {
  if (!userDb) return 0;
  let count = 0;
  const stmt = userDb.prepare('INSERT OR IGNORE INTO favorites (word,lang,phonetic,translation,context,created_at) VALUES (?,?,\'\',\'\',\'\',?)');
  for (const w of words) { if (w.trim()) { stmt.run(w.trim(), lang || 'en', Date.now()); count++; } }
  return count;
});

