  for (const b of boxes) {
    const cnt = allVocabList.filter(w => w.box === b).length;
    addTab('📦 ' + b, b, cnt);
  }

  // 过滤当前箱子
  let filtered = allVocabList;
  if (currentBox === '__unboxed__') filtered = allVocabList.filter(w => !w.box);
