});

// 选词成图
document.getElementById('vocabSelImageBtn').addEventListener('click', async () => {
  if (selectedWordIds.size === 0) return;
  const selected = allVocabList.filter(w => selectedWordIds.has(w.id));
  imgModal.classList.add('show');
  const cards = document.getElementById('imgCards');
  cards.innerHTML = '<div style="color:var(--text-dim);padding:20px">🎨 AI生成场景图...</div>';

  const wordDetails = selected.map(w => ({ word: w.word, translation: w.translation || '' }));
  const words = selected.map(w => w.word);
  const title = currentBox && currentBox !== '__unboxed__' ? currentBox : '我的词汇';

  const imgPrompt = `A colorful illustrated scene about "${title}" that visually represents these objects/concepts: ${words.join(', ')}. Each item should be clearly visible and identifiable in the scene. Style: clean educational illustration, bright colors, white/light background, flat design, no text or labels in the image.`;
  let aiImg = null;
  try { aiImg = await ipcRenderer.invoke('ai-generate-image', imgPrompt); } catch(e) {}

  const dataUrl = await renderSceneWithLabels(title, wordDetails, aiImg);
  cards.innerHTML = '';
  const div = document.createElement('div');
  div.className = 'img-card';
  div.innerHTML = `<img src="${dataUrl}" style="max-width:520px;border-radius:12px;box-shadow:0 4px 20px rgba(0,0,0,0.2)"><button class="btn btn-small" style="margin-top:6px">💾 保存</button>`;
  div.querySelector('button').addEventListener('click', () => {
    const a = document.createElement('a'); a.href = dataUrl; a.download = title + '.png'; a.click();
  });
  cards.appendChild(div);
});

