document.getElementById('vocabAutoClassBtn').addEventListener('click', async () => {
  if (!allVocabList.length) { alert('词书为空'); return; }
  imgModal.classList.add('show');
  const cards = document.getElementById('imgCards');
  cards.innerHTML = '<div style="color:var(--text-dim);padding:20px">🤖 AI分类词汇中...</div>';

  const wordMap = {};
  for (const item of allVocabList) wordMap[item.word] = item;
  const words = allVocabList.map(w => w.word);

  // 1. AI分组
  let groups;
  try {
    const raw = await ipcRenderer.invoke('ai-group-words', words);
    groups = JSON.parse(raw);
  } catch(e) {
    groups = [{ group: '全部词汇', words }];
  }

  // 2. 自动分配箱子
  for (const g of groups) {
    const ids = g.words.map(w => wordMap[w]?.id).filter(Boolean);
    if (ids.length) await ipcRenderer.invoke('fav-batch-set-box', ids, g.group);
  }
  loadVocabList();

  // 3. 逐组生成故事+场景图
  cards.innerHTML = '';
  for (const g of groups) {
    const div = document.createElement('div');
    div.className = 'img-card';
    div.style.maxWidth = '540px';
    div.innerHTML = `<div style="padding:20px;background:var(--sub-bg);border-radius:12px;color:var(--text-dim);text-align:center">📝 生成故事: ${g.group}...</div>`;
    cards.appendChild(div);

    const translations = g.words.map(w => wordMap[w]?.translation || '');
    const wordDetails = g.words.map(w => ({ word: w, translation: wordMap[w]?.translation || '' }));

    // AI讲故事
    let story = '';
    let imgDesc = '';
    try {
      const raw = await ipcRenderer.invoke('ai-story-with-words', g.group, g.words, translations);
      story = raw || '';
      // 提取画面描述
      const descMatch = story.match(/【画面描述】(.+)/);
      if (descMatch) {
        imgDesc = descMatch[1].trim();
        story = story.replace(/【画面描述】.+/, '').trim();
      }
    } catch(e) {}

    // AI生成场景图
    let aiImg = null;
    const imgPrompt = imgDesc || `A vivid illustrated scene about "${g.group}" showing: ${g.words.join(', ')}. Educational illustration, colorful, detailed, no text.`;
    div.querySelector('div').textContent = `🎨 AI绘制场景图: ${g.group}...`;
    try { aiImg = await ipcRenderer.invoke('ai-generate-image', imgPrompt); } catch(e) {}
    if (!aiImg) div.querySelector('div').textContent = `🖌 本地渲染: ${g.group}...`;

    // 合成：场景图 + 词汇标注
    const dataUrl = await renderSceneWithLabels(g.group, wordDetails, aiImg);

    // 渲染卡片：故事 + 图片
    div.innerHTML = '';
    // 故事文本
    if (story) {
      const storyDiv = document.createElement('div');
      storyDiv.style.cssText = 'padding:12px 16px;background:var(--sub-bg);border-radius:12px 12px 0 0;font-size:13px;line-height:1.8;color:var(--text);max-height:200px;overflow-y:auto';
      // 高亮故事中的词汇
      let storyHtml = story;
      for (const w of g.words) {
        storyHtml = storyHtml.replace(new RegExp(`\\b(${w})\\b`, 'gi'), '<b style="color:var(--accent)">$1</b>');
      }
      storyDiv.innerHTML = storyHtml.replace(/\n/g, '<br>');
      div.appendChild(storyDiv);

