1123→async function renderSceneWithLabels(title, wordDetails, aiImgUrl) {
1124→  const canvas = document.getElementById('imgCanvas');
1125→  const ctx = canvas.getContext('2d');
1126→  const W = 1024, H = 768;
1127→  canvas.width = W; canvas.height = H;
1128→
1129→  if (aiImgUrl) {
1130→    try {
1131→      const img = await loadImg(aiImgUrl);
1132→      ctx.drawImage(img, 0, 0, W, H);
1133→    } catch(e) {
1134→      drawFallbackBg(ctx, W, H, title);
1135→    }
1136→  } else {
1137→    drawFallbackBg(ctx, W, H, title);
1138→  }
1139→
1140→  // 半透明遮罩让标注更清晰
1141→  const grad = ctx.createLinearGradient(0, 0, 0, H);
1142→  grad.addColorStop(0, 'rgba(0,0,0,0.15)');
1143→  grad.addColorStop(0.4, 'rgba(0,0,0,0.05)');
1144→  grad.addColorStop(0.6, 'rgba(0,0,0,0.1)');
1145→  grad.addColorStop(1, 'rgba(0,0,0,0.55)');
1146→  ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);
1147→
1148→  // 顶部标题
1149→  ctx.font = 'bold 24px Microsoft YaHei UI';
1150→  const tw = ctx.measureText('📚 ' + title).width + 40;
1151→  ctx.fillStyle = 'rgba(91,122,94,0.9)';
1152→  rrect(ctx, 20, 16, tw, 48, 24); ctx.fill();
1153→  ctx.fillStyle = '#fff'; ctx.textAlign = 'left';
1154→  ctx.fillText('📚 ' + title, 40, 48);
1155→
1156→  // 词汇标注卡片 - 散布在画面中
1157→  const n = wordDetails.length;
1158→  const cols = Math.min(3, n);
1159→  const rows = Math.ceil(n / cols);
1160→  const cardW = 300, cardH = 62, gapX = 16, gapY = 14;
1161→  const gridW = cols * (cardW + gapX) - gapX;
1162→  const gridH = rows * (cardH + gapY) - gapY;
1163→  const ox = (W - gridW) / 2;
1164→  const oy = H - gridH - 40;
1165→
1166→  for (let i = 0; i < n; i++) {
1167→    const wd = wordDetails[i];
1168→    const col = i % cols, row = Math.floor(i / cols);
1169→    const x = ox + col * (cardW + gapX);
1170→    const y = oy + row * (cardH + gapY);
1171→
1172→    // 卡片背景 - 白色圆角带阴影
1173→    ctx.shadowColor = 'rgba(0,0,0,0.3)'; ctx.shadowBlur = 10; ctx.shadowOffsetY = 3;
1174→    ctx.fillStyle = 'rgba(255,255,255,0.92)';
1175→    rrect(ctx, x, y, cardW, cardH, 12); ctx.fill();
1176→    ctx.shadowColor = 'transparent'; ctx.shadowBlur = 0; ctx.shadowOffsetY = 0;
1177→
1178→    // 左侧色条
1179→    ctx.fillStyle = '#5b7a5e';
1180→    rrect(ctx, x, y, 6, cardH, 3); ctx.fill();
1181→
1182→    // 序号圆
1183→    ctx.fillStyle = '#5b7a5e';
1184→    ctx.beginPath(); ctx.arc(x + 22, y + 20, 10, 0, Math.PI * 2); ctx.fill();
1185→    ctx.fillStyle = '#fff'; ctx.font = 'bold 11px Microsoft YaHei UI'; ctx.textAlign = 'center';
1186→    ctx.fillText(String(i + 1), x + 22, y + 24);
1187→
1188→    // 单词
1189→    ctx.fillStyle = '#1a1a1a'; ctx.font = 'bold 20px Microsoft YaHei UI'; ctx.textAlign = 'left';
1190→    ctx.fillText(wd.word, x + 40, y + 26);
1191→
1192→    // 中文释义
1193→    if (wd.translation) {
1194→      ctx.fillStyle = '#5b7a5e'; ctx.font = '14px Microsoft YaHei UI';
1195→      ctx.fillText(wd.translation.slice(0, 24), x + 40, y + 50);
1196→    }
1197→  }
1198→
1199→  // 底部水印
1200→  ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.font = '11px Microsoft YaHei UI'; ctx.textAlign = 'center';
1201→  ctx.fillText('多语言视频学习 · 词汇场景图', W / 2, H - 10);
