1206→function drawFallbackBg(ctx, W, H, title) {
1207→  // 丰富的渐变背景
1208→  const colors = [
1209→    ['#667eea', '#764ba2'], ['#f093fb', '#f5576c'], ['#4facfe', '#00f2fe'],
1210→    ['#43e97b', '#38f9d7'], ['#fa709a', '#fee140'], ['#a18cd1', '#fbc2eb']
1211→  ];
1212→  const pair = colors[Math.abs(title.charCodeAt(0)) % colors.length];
1213→  const grad = ctx.createLinearGradient(0, 0, W, H);
1214→  grad.addColorStop(0, pair[0]); grad.addColorStop(1, pair[1]);
1215→  ctx.fillStyle = grad; ctx.fillRect(0, 0, W, H);
1216→
1217→  // 装饰元素 - 大圆、小圆、波浪
1218→  ctx.globalAlpha = 0.12;
1219→  for (let i = 0; i < 8; i++) {
1220→    const cx = Math.random() * W, cy = Math.random() * H * 0.7, r = 40 + Math.random() * 100;
1221→    ctx.fillStyle = '#fff';
1222→    ctx.beginPath(); ctx.arc(cx, cy, r, 0, Math.PI * 2); ctx.fill();
1223→  }
1224→  // 底部波浪
1225→  ctx.fillStyle = 'rgba(255,255,255,0.15)';
1226→  ctx.beginPath(); ctx.moveTo(0, H * 0.65);
1227→  for (let x = 0; x <= W; x += 20) {
1228→    ctx.lineTo(x, H * 0.65 + Math.sin(x * 0.015) * 30 + Math.sin(x * 0.008) * 20);
1229→  }
1230→  ctx.lineTo(W, H); ctx.lineTo(0, H); ctx.fill();
1231→  ctx.globalAlpha = 1;
1232→}
