1234→function rrect(ctx, x, y, w, h, r) {
1235→  ctx.beginPath(); ctx.moveTo(x + r, y); ctx.lineTo(x + w - r, y);
1236→  ctx.quadraticCurveTo(x + w, y, x + w, y + r); ctx.lineTo(x + w, y + h - r);
1237→  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h); ctx.lineTo(x + r, y + h);
1238→  ctx.quadraticCurveTo(x, y + h, x, y + h - r); ctx.lineTo(x, y + r);
1239→  ctx.quadraticCurveTo(x, y, x + r, y); ctx.closePath();
1240→}
